CREATE DEFINER=`root`@`localhost` PROCEDURE `createStudent` (IN `p_user_id` INT, IN `p_student_name` VARCHAR(255), IN `p_student_number` VARCHAR(50), IN `p_course_id` INT, IN `p_birthday` DATE, IN `p_img` LONGBLOB)   BEGIN
    IF p_img IS NULL THEN
        INSERT INTO students (user_id, student_name, student_number, course_id, birthday, img)
        VALUES (p_user_id, p_student_name, p_student_number, p_course_id, p_birthday, NULL);
    ELSE
        INSERT INTO students (user_id, student_name, student_number, course_id, birthday, img)
        VALUES (p_user_id, p_student_name, p_student_number, p_course_id, p_birthday, p_img);
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `createUser` (IN `usernameInput` VARCHAR(100), IN `passwordInput` VARCHAR(255), IN `roleInput` VARCHAR(20))   INSERT INTO users (username, password_hash, role) 
VALUES (usernameInput, passwordInput, roleInput)$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `deleteGrade` (IN `p_student_id` INT, IN `p_subject_id` INT, IN `p_semester` VARCHAR(20), IN `p_school_year` VARCHAR(20))   DELETE FROM grades
WHERE student_id = p_student_id AND
      subject_id = p_subject_id AND 
      semester = p_semester AND
      school_year = p_school_year$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getAdminByUserId` (IN `adminId` INT)   SELECT admin_id FROM admins WHERE user_id = adminId$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getAllStudents` ()   SELECT 
            s.student_id, 
            s.student_number, 
            s.student_name, 
            c.course_name
        FROM students s
        JOIN courses c ON s.course_id = c.course_id
        ORDER BY s.student_name ASC$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getCourseList` ()   SELECT course_id, course_name FROM courses ORDER BY course_name$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getStudentBySearch` (IN `inputSearch` VARCHAR(100))   SELECT 
	s.student_id, 
	s.student_number, 
	s.student_name, 
	c.course_name
FROM students s
JOIN courses c ON s.course_id = c.course_id
	WHERE s.student_name LIKE inputSearch
	OR s.student_number LIKE inputSearch
	OR c.course_name LIKE inputSearch
ORDER BY s.student_name ASC$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getStudentByUserId` (IN `userIdInput` INT)   SELECT * FROM students WHERE user_id = userIdInput$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getStudentDetailsByStudentId` (IN `studentId` INT)   SELECT
        s.student_id,
        s.student_name,
        s.student_number,
        s.course_id,
        s.birthday,
        s.img,
        u.user_id,
        u.username
    FROM students s
    JOIN users u ON s.user_id = u.user_id
    WHERE s.student_id = studentId$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getSubjectsByStudentId` (IN `studentId` INT)   SELECT 
        s.subject_id,
        s.subject_code,
        s.units,
        curr.subject_name,
        g.grade,
        curr.year_level,
        curr.semester
    FROM students stu
    JOIN curriculum curr ON curr.course_id = stu.course_id
    JOIN subjects s ON s.subject_id = curr.subject_id
    LEFT JOIN grades g
        ON g.student_id = stu.student_id
        AND g.subject_id = s.subject_id
    WHERE stu.student_id = studentId
    ORDER BY curr.year_level, curr.semester, s.subject_code$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getUserAccountDetails` (IN `studentId` INT)   SELECT u.user_id, u.password_hash, u.username
FROM students st
JOIN users u ON st.user_id = u.user_id
WHERE st.student_id = studentId$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `getUserDetailByUsername` (IN `usernameInput` VARCHAR(100))   SELECT user_id, password_hash, role 
FROM users 
WHERE username = usernameInput AND is_active = 1$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `updateStudent` (IN `p_name` VARCHAR(100), IN `p_number` VARCHAR(100), IN `p_course_id` INT, IN `p_birthday` DATE, IN `p_img` LONGBLOB, IN `p_student_id` INT)   BEGIN
    IF p_img IS NULL OR p_img = '' THEN
        UPDATE students 
        SET student_name = p_name, 
            student_number = p_number, 
            course_id = p_course_id, 
            birthday = p_birthday
        WHERE student_id = p_student_id;
    ELSE
        UPDATE students 
        SET student_name = p_name, 
            student_number = p_number, 
            course_id = p_course_id, 
            birthday = p_birthday,
            img = p_img
        WHERE student_id = p_student_id;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `updateUser` (IN `p_username` VARCHAR(100), IN `p_password_hash` VARCHAR(255), IN `p_user_id` INT)   BEGIN
    IF p_password_hash IS NULL OR p_password_hash = '' THEN
        UPDATE users SET username = p_username WHERE user_id = p_user_id;
    ELSE
        UPDATE users SET username = p_username, password_hash = p_password_hash WHERE user_id = p_user_id;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `upsertGrade` (IN `p_student_id` INT, IN `p_subject_id` INT, IN `p_semester_grade` DECIMAL(3,2), IN `p_average_grade` DECIMAL(5,2), IN `p_prelim` DECIMAL(5,2), IN `p_midterm` DECIMAL(5,2), IN `p_prefinal` DECIMAL(5,2), IN `p_finals` DECIMAL(5,2), IN `p_remarks` VARCHAR(50), IN `p_semester` VARCHAR(20), IN `p_school_year` VARCHAR(20))   BEGIN
    INSERT INTO grades (
        student_id, subject_id, semester_grade, 
        average_grade, prelim, midterm, prefinal, finals, 
        remarks, semester, school_year
    ) VALUES (
        p_student_id, p_subject_id, p_semester_grade, 
        p_average_grade, p_prelim, p_midterm, p_prefinal, p_finals, 
        p_remarks, p_semester, p_school_year
    )
    ON DUPLICATE KEY UPDATE 
        semester_grade = VALUES(semester_grade),
        average_grade = VALUES(average_grade),
        prelim = VALUES(prelim),
        midterm = VALUES(midterm),
        prefinal = VALUES(prefinal),
        finals = VALUES(finals),
        remarks = VALUES(remarks);
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `UserUpdatePassword` (IN `p_new_hash` VARCHAR(255), IN `p_user_id` INT)   UPDATE users SET password_hash = p_new_hash WHERE user_id = p_user_id$$

